sn_aia_tool.script:
(function(inputs) {
    var serial = inputs.serial_number;
    var gr = new GlideRecord('cmdb_ci_med_device');
    gr.addQuery('serial_number', serial);
    gr.setLimit(1);
    gr.query();
    if (gr.next()) {
        var companyName = '';
        if (gr.getValue('company')) {
            var comp = new GlideRecord('core_company');
            if (comp.get(gr.getValue('company'))) {
                companyName = comp.getValue('name');
            }
        }
        return JSON.stringify({
            status: 'success',
            records: [{
                sys_id: gr.getValue('sys_id'),
                name: gr.getValue('name'),
                serial_number: gr.getValue('serial_number'),
                warranty_expiration: gr.getValue('warranty_expiration'),
                short_description: gr.getValue('short_description'),
                company: companyName,
                company_sys_id: gr.getValue('company')
            }],
            message: 'Device found: ' + gr.getValue('name')
        });
    } else {
        return JSON.stringify({
            status: 'not_found',
            records: [],
            message: 'No device found with serial number: ' + serial
        });
    }
})(inputs);
